mapper.update:
UPDATE email_verification
SET expired_at = CASE WHEN expired_at > NOW() THEN NOW() ELSE expired_at END
WHERE email = #{email}
  AND purpose = #{purpose}
  AND used = 0

mapper.delete:
DELETE FROM native_auth_handoff
 WHERE id = #{id}
   AND expired_at > NOW()

mapper.insert:
INSERT INTO user_login_history (
    user_id, event_type, auth_provider, login_method, login_identifier,
    success, fail_reason, ip_address, user_agent, request_uri
)
VALUES (
    #{userId}, #{eventType}, #{authProvider}, #{loginMethod}, #{loginIdentifier},
    #{success}, #{failReason}, #{ipAddress}, #{userAgent}, #{requestUri}
)

INSERT INTO user_status_history (
    user_id, actor_user_id, previous_status, new_status, reason, memo, blocked_until
)
VALUES (
    #{userId}, #{actorUserId}, #{previousStatus}, #{newStatus}, #{reason}, #{memo}, #{blockedUntil}
)
